local LFightExpreBase = LXImport("..Base.LFightExpreBase")
---@class LFightExpreHitHud:LFightExpreBase
local LFightExpreHitHud = LxClass("LFightExpreHitHud",LFightExpreBase)

function LFightExpreHitHud:LFightExpreHitHud()
    self._type = LSkillEffConst.PLAY_EFF_HIT_HUD
end

function LFightExpreHitHud:Preload()

end

function LFightExpreHitHud:OnStart()

    local effData = self._effData
    --动作时间
    local time = effData.playTime
    --动作名字
    local ani = LSpineAniConst.hit1

    ---@type LFightObject
    local targetObj = self._runningData.targetObj
    ---@type LFightObject[]
    local targetObjs = self._runningData.targetObjs
    if targetObjs and #targetObjs > 0 then
        for i,v in ipairs(targetObjs) do
            if not v:IsDead() then
                v:SetSkillPlaying(true)
                v:PlayAni(ani, false, time)
            end
        end
    elseif targetObj then
        if not targetObj:IsDead() then
            targetObj:SetSkillPlaying(true)
            targetObj:PlayAni(ani, false, time)
        end
    end
end

return LFightExpreHitHud